import threading

app = Flask(__name__)

MAX_UNIQUE_COMBINATIONS = 1000
MAX_PATH_SEGMENTS = 3

class CardinalityLimitedMetrics:
    def __init__(self, max_combinations=MAX_UNIQUE_COMBINATIONS):
        self.max_combinations = max_combinations
        self.lock = threading.Lock()
        self.tracked_combinations = set()
        self.combination_count = defaultdict(int)
        
        self.http_requests_total = Counter(
            'http_requests_total',
            'Total HTTP requests',
            ['method', 'status', 'normalized_path']
        )
        
        self.http_request_duration_seconds = Histogram(
            'http_request_duration_seconds',
            'HTTP request duration',
            ['method', 'normalized_path']
        )
        
        self.http_requests_by_user_path = Counter(
            'http_requests_by_user_path',
            'HTTP requests by user and path (limited cardinality)',
            ['user_hash', 'normalized_path']
        )
        
        self.dropped_combinations = Counter(
            'metrics_dropped_combinations_total',
            'Number of dropped metric combinations due to cardinality limit'
        )
        
    def normalize_path(self, path):
        parts = path.strip('/').split('/')
        
        normalized_parts = []
        for i, part in enumerate(parts[:MAX_PATH_SEGMENTS]):
            if part.isdigit() or len(part) > 20 or self._looks_like_id(part):
                normalized_parts.append(':id')
            else:
                normalized_parts.append(part)
        
        if len(parts) > MAX_PATH_SEGMENTS:
            normalized_parts.append('...')
            
        return '/' + '/'.join(normalized_parts) if normalized_parts else '/'
    
    def _looks_like_id(self, segment):
        if len(segment) > 20:
            return True
        if '-' in segment and len(segment) > 10:
            return True
        try:
            int(segment, 16)
            if len(segment) > 8:
                return True
        except ValueError:
            pass
        return False
    
    def hash_user_id(self, user_id):
        if not user_id:
            return 'anonymous'
        hash_obj = hashlib.sha256(str(user_id).encode())
        return hash_obj.hexdigest()[:16]
    
    def should_track_combination(self, user_hash, normalized_path):
        combination_key = f"{user_hash}:{normalized_path}"
        
        with self.lock:
            if combination_key in self.tracked_combinations:
                self.combination_count[combination_key] += 1
                return True
            
            if len(self.tracked_combinations) < self.max_combinations:
                self.tracked_combinations.add(combination_key)
                self.combination_count[combination_key] = 1
                return True
            
            self.dropped_combinations.inc()
            return False
    
    def track_request(self, method, path, user_id, status_code, duration):
        normalized_path = self.normalize_path(path)
        
        self.http_requests_total.labels(
            method=method,
            status=str(status_code),
            normalized_path=normalized_path
        ).inc()
        
        self.http_request_duration_seconds.labels(
            method=method,
            normalized_path=normalized_path
        ).observe(duration)
        
        user_hash = self.hash_user_id(user_id)
        
        if self.should_track_combination(user_hash, normalized_path):
            self.http_requests_by_user_path.labels(
                user_hash=user_hash,
                normalized_path=normalized_path
            ).inc()

